<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>2048</title>
    <style>
        :root {
            --color-bg: #222;
            --color-board-bg: #333;
            --color-text: #eee;
            --tile-size: 100px;
            --gap: 10px;
        }

        body {
            font-family: 'Arial', sans-serif;
            background-color: var(--color-bg);
            color: var(--color-text);
            display: flex;
            flex-direction: column;
            align-items: center;
            padding: 20px;
            margin: 0;
        }

        #game-container {
            display: flex;
            flex-direction: column;
            align-items: center;
            max-width: 450px; /* Constrain overall width */
        }

        #header {
            display: flex;
            justify-content: space-between;
            width: 100%;
            margin-bottom: 20px;
            padding: 10px 0;
        }

        #score-container, #reset-container {
            background-color: var(--color-board-bg);
            padding: 10px 20px;
            border-radius: 6px;
            font-size: 1.5em;
            text-align: center;
        }

        #score {
            font-weight: bold;
        }

        /* Board Styling */
        #board {
            display: grid;
            grid-template-columns: repeat(4, var(--tile-size));
            grid-template-rows: repeat(4, var(--tile-size));
            gap: var(--gap);
            background-color: #1a1a1a; /* Darker background for the grid area */
            padding: 20px;
            border-radius: 8px;
            box-shadow: 0 4px 15px rgba(0, 0, 0, 0.3);
        }

        /* Tile Styling */
        .tile {
            width: var(--tile-size);
            height: var(--tile-size);
            display: flex;
            justify-content: center;
            align-items: center;
            font-size: 3em;
            font-weight: bold;
            border-radius: 6px;
            transition: transform 0.1s ease-in-out, background-color 0.1s ease-in-out;
            user-select: none;
        }

        /* Tile Colors (Standard 2048 palette) */
        .tile[data-value="2"] { background-color: #eee4da; color: #776e65; }
        .tile[data-value="4"] { background-color: #ede0c8; color: #776e65; }
        .tile[data-value="8"] { background-color: #f2b179; color: #f9f6f2; }
        .tile[data-value="16"] { background-color: #f5955a; color: #f9f6f2; }
        .tile[data-value="32"] { background-color: #e67e22; color: #f9f6f2; }
        .tile[data-value="64"] { background-color: #d98a00; color: #f9f6f2; }
        .tile[data-value="128"] { background-color: #a29bfe; color: #f9f6f2; }
        .tile[data-value="256"] { background-color: #4a3c7d; color: #f9f6f2; }
        .tile[data-value="512"] { background-color: #3e2b80; color: #f9f6f2; }
        /* Add more colors if needed, but these cover the standard range */

        /* Button Styling */
        #reset {
            padding: 10px 25px;
            font-size: 1.2em;
            cursor: pointer;
            background-color: #8f7a66;
            color: white;
            border: none;
            border-radius: 6px;
            margin-top: 20px;
            transition: background-color 0.1s;
        }

        #reset:hover {
            background-color: #9e8a75;
        }
    </style>
</head>
<body>

    <div id="game-container">
        <header id="header">
            <div id="score-container">Score: <span id="score">0</span></div>
            <button id="reset">New Game</button>
        </header>

        <!-- The 4x4 grid will be populated here -->
        <div id="board">
            <!-- Tiles are dynamically inserted here by JS -->
        </div>
    </div>


    <script>
        // ==================================================
        // CORE GAME LOGIC AND STATE MANAGEMENT
        // ==================================================

        const BOARD_SIZE = 4;
        let gameBoard = [];
        let scoreValue = 0;

        /**
         * Initializes the game state.
         */
        function initializeGame() {
            gameBoard = Array(BOARD_SIZE).fill(0).map(() => Array(BOARD_SIZE).fill(0));
            scoreValue = 0;
            updateScoreDisplay();
            renderBoard();

            // Start with exactly 2 tiles (2 and 4)
            spawnInitialTiles(2);
        }

        /**
         * Helper function to place initial tiles at random empty spots.
         * @param {number} count - Number of tiles to spawn.
         */
        function spawnInitialTiles(count) {
            for (let i = 0; i < count; i++) {
                const r = Math.floor(Math.random() * BOARD_SIZE);
                const c = Math.floor(Math.random() * BOARD_SIZE);

                if (gameBoard[r][c] === 0) {
                    // Bias towards 2, occasionally 4
                    let value;
                    if (Math.random() < 0.85) {
                        value = 2;
                    } else {
                        value = 4;
                    }
                    gameBoard[r][c] = value;
                }
            }
        }

        /**
         * Updates the visible score element in the DOM.
         */
        function updateScoreDisplay() {
            document.getElementById('score').textContent = scoreValue;
        }

        /**
         * Renders the current gameBoard state to the DOM, updating tile classes and values.
         */
        function renderBoard() {
            const boardElement = document.getElementById('board');
            // Clear existing tiles
            boardElement.innerHTML = '';

            for (let r = 0; r < BOARD_SIZE; r++) {
                for (let c = 0; c < BOARD_SIZE; c++) {
                    const value = gameBoard[r][c];
                    if (value !== 0) {
                        const tile = document.createElement('div');
                        tile.className = 'tile';
                        tile.setAttribute('data-value', value);
                        tile.textContent = value;
                        boardElement.appendChild(tile);
                    } else {
                        // Create a placeholder div to maintain the grid structure, but keep it empty/invisible
                        const tilePlaceholder = document.createElement('div');
                        tilePlaceholder.className = 'tile';
                        tilePlaceholder.setAttribute('data-value', 0);
                        tilePlaceholder.textContent = '';
                        boardElement.appendChild(tilePlaceholder);
                    }
                }
            }
        }

        /**
         * Core logic for sliding and merging tiles in a single line (row or column).
         * @param {Array<number>} line - The 1D array representing the row/column.
         * @returns {{newLine: Array<number>, scoreIncrease: number, moved: boolean}}
         */
        function processLine(line) {
            let newTiles = [];
            let scoreIncrease = 0;
            let changed = false;

            // 1. Filter out zeros (compress)
            let filtered = line.filter(val => val !== 0);

            if (filtered.length === 0) {
                return { newLine: [...line], scoreIncrease: 0, moved: false };
            }

            // 2. Handle merges and build the new list
            let i = 0;
            while (i < filtered.length) {
                const current = filtered[i];
                if (i + 1 < filtered.length && current === filtered[i + 1]) {
                    // Merge occurs
                    const mergedValue = current * 2;
                    newTiles.push(mergedValue);
                    scoreIncrease += mergedValue;

                    // Skip the next tile as it was consumed in the merge
                    i += 2; 
                } else {
                    // No merge, just slide
                    newTiles.push(current);
                    i += 1;
                }
            }

            // 3. Pad with zeros to match original size
            while (newTiles.length < BOARD_SIZE) {
                newTiles.push(0);
            }

            // Check if anything actually changed from the original line
            let moved = false;
            for (let j = 0; j < BOARD_SIZE; j++) {
                if (line[j] !== newTiles[j]) {
                    moved = true;
                    break;
                }
            }

            return { newLine: newTiles, scoreIncrease: scoreIncrease, moved: moved };
        }


        /**
         * Executes the move logic based on direction.
         * @param {'up'|'down'|'left'|'right'} direction - The direction of movement.
         * @returns {boolean} True if any tile moved or merged, false otherwise.
         */
        function executeMove(direction) {
            let totalScoreIncrease = 0;
            let boardChanged = false;

            // Create a copy to track changes before applying them
            const originalBoard = JSON.parse(JSON.stringify(gameBoard));
            let newBoard = JSON.parse(JSON.stringify(gameBoard));

            if (direction === 'left' || direction === 'right') {
                // Process rows
                for (let r = 0; r < BOARD_SIZE; r++) {
                    let line = [];
                    if (direction === 'left') {
                        line = gameBoard[r]; // Row is already correctly ordered for left movement
                    } else { // right
                        // Reverse the row, process it as if moving left, then reverse back.
                        line = [...gameBoard[r]].reverse(); 
                    }

                    const result = processLine(line);
                    let newLine;
                    if (direction === 'left') {
                        newLine = result.newLine;
                    } else { // right
                        // Reverse the processed line back to original row order
                        newLine = [...result.newLine].reverse(); 
                    }

                    // Update the new board state for this row
                    for(let c=0; c<BOARD_SIZE; c++) {
                        newBoard[r][c] = newLine[c];
                    }
                    totalScoreIncrease += result.scoreIncrease;
                }
            } else { // Up or Down (Process columns)
                // Process columns
                for (let c = 0; c < BOARD_SIZE; c++) {
                    let line = [];
                    if (direction === 'up') {
                        // Column elements are already top-to-bottom
                        line = Array(BOARD_SIZE).fill(0).map((_, r) => gameBoard[r][c]);
                    } else { // down
                        // Process bottom-to-top, then reverse the result.
                        line = [];
                        for (let r = BOARD_SIZE - 1; r >= 0; r--) {
                            line.push(gameBoard[r][c]);
                        }
                    }

                    const result = processLine(line);
                    let newLine;
                    if (direction === 'up') {
                        newLine = result.newLine;
                    } else { // down
                        // Reverse the processed line back to original column order (bottom-to-top)
                        newLine = [...result.newLine].reverse(); 
                    }

                    // Update the new board state for this column
                    for(let r=0; r<BOARD_SIZE; r++) {
                        newBoard[r][c] = newLine[r];
                    }
                    totalScoreIncrease += result.scoreIncrease;
                }
            }

            // Check if any change occurred across the entire board
            for (let r = 0; r < BOARD_SIZE; r++) {
                for (let c = 0; c < BOARD_SIZE; c++) {
                    if (originalBoard[r][c] !== newBoard[r][c]) {
                        boardChanged = true;
                        break;
                    }
                }
                if (boardChanged) break;
            }

            // Apply changes if any occurred
            gameBoard = newBoard;
            const moved = boardChanged;

            if (moved) {
                scoreValue += totalScoreIncrease;
                updateScoreDisplay();
                renderBoard(); // Re-render the entire board to show movement/merges

                // Spawn new tile
                spawnNewTile();
            }

            return moved;
        }


        /**
         * Spawns a single random tile (2 or 4) on an empty spot.
         */
        function spawnNewTile() {
            const emptyCells = [];
            for (let r = 0; r < BOARD_SIZE; r++) {
                for (let c = 0; c < BOARD_SIZE; c++) {
                    if (gameBoard[r][c] === 0) {
                        emptyCells.push({ r, c });
                    }
                }
            }

            if (emptyCells.length > 0) {
                const cell = emptyCells[Math.floor(Math.random() * emptyCells.length)];
                let value;
                // Bias towards 2, occasionally 4
                value = Math.random() < 0.85 ? 2 : 4;
                gameBoard[cell.r][cell.c] = value;
            }
        }

        /**
         * Public API: Resets the game state and starts a new game.
         */
        function resetGame() {
            initializeGame();
        }


        // ==================================================
        // WINDOW GLOBAL API EXPOSURE (Grading Contract)
        // ==================================================

        window.game = {
            size: BOARD_SIZE,

            /**
             * Starts a new game with 2 tiles and score 0.
             */
            reset: function() {
                initializeGame();
            },

            /**
             * Attempts to move the tiles in the given direction.
             * @param {'left'|'right'|'up'|'down'} direction
             * @returns {boolean} True if anything moved/merged, false otherwise.
             */
            move: function(direction) {
                return executeMove(direction);
            },

            /**
             * Returns a deep copy of the current 4x4 board state.
             * @returns {Array<Array<number>>}
             */
            board: function() {
                return JSON.parse(JSON.stringify(gameBoard));
            },

            /**
             * Sets the internal game board state exactly (used by grading harness).
             * Note: This bypasses movement rules and does not spawn tiles or update score automatically.
             * @param {Array<Array<number>>} arr - The 4x4 array to set the board to.
             */
            setBoard: function(arr) {
                if (arr && arr.length === BOARD_SIZE && arr[0].length === BOARD_SIZE) {
                    gameBoard = JSON.parse(JSON.stringify(arr));
                    renderBoard();
                } else {
                    console.error("Invalid board array provided to setBoard.");
                }
            },

            /**
             * Returns the current score value.
             */
            score: function() {
                return scoreValue;
            }
        };


        // ==================================================
        // EVENT LISTENERS AND INITIAL SETUP
        // ==================================================

        document.addEventListener('DOMContentLoaded', () => {
            // 1. Initial Setup
            initializeGame();

            // 2. Key Input Handler (Arrow Keys)
            document.addEventListener('keydown', (e) => {
                let direction = null;
                switch (e.key) {
                    case 'ArrowLeft':
                        direction = 'left';
                        break;
                    case 'ArrowRight':
                        direction = 'right';
                        break;
                    case 'ArrowUp':
                        direction = 'up';
                        break;
                    case 'ArrowDown':
                        direction = 'down';
                        break;
                    default:
                        return; // Ignore other keys
                }

                e.preventDefault(); // Prevent scrolling
                const moved = window.game.move(direction);
            });

            // 3. Reset Button Handler
            document.getElementById('reset').addEventListener('click', () => {
                window.game.reset();
            });
        });

    </script>
</body>
</html>
